public class Codec {

    // Encodes a tree to a single string.
    public String serialize(TreeNode root) {
        StringBuilder sb = new StringBuilder();
        serialize(root, sb);
        return sb.toString();
    }

    private void serialize(TreeNode node, StringBuilder sb) {
        if (node == null) return;
        sb.append(node.val).append(",");
        serialize(node.left, sb);
        serialize(node.right, sb);
    }

    // Decodes your encoded data to tree.
    public TreeNode deserialize(String data) {
        if (data.isEmpty()) return null;
        String[] vals = data.split(",");
        int[] idx = new int[1];
        return build(Integer.MIN_VALUE, Integer.MAX_VALUE, vals, idx);
    }

    private TreeNode build(int lower, int upper, String[] vals, int[] idx) {
        if (idx[0] >= vals.length) return null;
        int val = Integer.parseInt(vals[idx[0]]);
        if (val < lower || val > upper) return null;
        idx[0]++;
        TreeNode node = new TreeNode(val);
        node.left = build(lower, val, vals, idx);
        node.right = build(val, upper, vals, idx);
        return node;
    }
}
